{
  "summary": "19世纪末的伦敦，天才侦探夏洛克·福尔摩斯与退役军医约翰·华生合租贝克街221B，凭借超凡的观察力与演绎推理，破解警方束手无策的奇案。从《血字的研究》初次合作，到追踪莫里亚蒂教授的地下犯罪帝国，两人历经《波希米亚丑闻》中对艾琳·艾德勒的尊重与挫败，《巴斯克维尔的猎犬》的家族诅咒，《最后一案》中与宿敌在莱辛巴赫瀑布的殊死搏斗。福尔摩斯“假死”归来后再度携手华生，继续对抗伦敦暗处的罪恶。系列故事不仅展现缜密推理，更刻画了两人超越友情的羁绊、福尔摩斯的孤傲与脆弱，以及维多利亚时代社会的缩影。",
  "characters": [
    {
      "name": "夏洛克·福尔摩斯",
      "role_in_story": "第一主角，顾问侦探",
      "relation_to_protagonist": "本人",
      "traits": ["冷静孤傲", "观察入微", "博学但偏科", "偶尔使用可卡因", "厌恶社交但依赖华生"],
      "must_have": true,
      "voice_style": "语速快、精准、略带刻薄，常用“我亲爱的华生，你看到却没有观察”句式。",
      "story_arc": "从纯粹的逻辑机器，因华生的友谊与艾琳的触动逐渐显露人性，最终在与莫里亚蒂的对决中完成自我牺牲与重生，领悟情感的价值。"
    },
    {
      "name": "约翰·H·华生",
      "role_in_story": "第一人称叙述者，福尔摩斯的助手与挚友",
      "relation_to_protagonist": "室友、传记作者、生死之交",
      "traits": ["忠诚勇敢", "善良温和", "坚毅的军人气质", "医学知识实用", "常被福尔摩斯的推理折服"],
      "must_have": true,
      "voice_style": "敬佩中略带无奈，记录详实，常以“我亲爱的福尔摩斯”回应，叙事口吻温和而充满信赖。",
      "story_arc": "从战争伤残军官到成为侦探搭档，在与福尔摩斯的冒险中重拾生活意义，结婚后一度离开，但最终仍被拉回冒险世界，证明友情的不可替代性。"
    },
    {
      "name": "詹姆斯·莫里亚蒂教授",
      "role_in_story": "首要反派，犯罪界的拿破仑",
      "relation_to_protagonist": "宿敌，智力与势力的终极对立者",
      "traits": ["数学天才", "冷血缜密", "庞大的犯罪网络", "表面温文尔雅", "极度危险"],
      "must_have": true,
      "voice_style": "彬彬有礼中透出绝对掌控，以学术比喻犯罪，如“一个方程式中的微小错误便会毁掉一切”。",
      "story_arc": "从暗处操控欧洲犯罪网的顶峰，因福尔摩斯的步步紧逼而被迫正面对抗，最终在莱辛巴赫坠崖，成为福尔摩斯生涯的转折点。"
    },
    {
      "name": "哈德森太太",
      "role_in_story": "贝克街221B的房东，日常照料者",
      "relation_to_protagonist": "房东与几乎家人的关系",
      "traits": ["慈祥但坚韧", "对古怪房客极度包容", "偶尔抱怨但忠心不二"],
      "must_have": false,
      "voice_style": "略带唠叨却充满温暖，“天哪，福尔摩斯先生，你不能在室内开枪！”那种无奈的纵容。",
      "story_arc": "始终是两人冒险生活的稳定后方，以沉默的方式见证了一切，代表普通生活对天才怪癖的接纳。"
    },
    {
      "name": "雷斯垂德探长",
      "role_in_story": "苏格兰场警官，经常求助福尔摩斯",
      "relation_to_protagonist": "专业上的合作者与偶尔的竞争者",
      "traits": ["勤勉但平庸", "务实", "对福尔摩斯既不屑又暗中佩服"],
      "must_have": false,
      "voice_style": "官方腔调，时而恼羞成怒，“我们警察也不是吃干饭的，福尔摩斯先生”但最终会感谢。",
      "story_arc": "从最初抵触业余侦探插手，到逐渐成为福尔摩斯在官方渠道的重要盟友，代表了体制内对天才的妥协与认可。"
    },
    {
      "name": "艾琳·艾德勒",
      "role_in_story": "唯一击败过福尔摩斯的女性，女高音歌唱家",
      "relation_to_protagonist": "智力上的对手与尊敬的对象，福尔摩斯口中的“那个女人”",
      "traits": ["聪慧机警", "独立自主", "勇敢为了爱情行动", "优雅且善于演戏"],
      "must_have": false,
      "voice_style": "从容自信，略带挑逗，面对福尔摩斯时不落下风，“晚安，歇洛克·福尔摩斯先生”的优雅退场。",
      "story_arc": "仅出场一次便成为传奇，她证明情感并非弱点，反而可以成为抵御冷酷推理的盾牌，改变了福尔摩斯对女性的看法。"
    }
  ],
  "places": [
    {
