{
  "summary": "系列剧讲述唐朝武周时期，宰相狄仁杰凭借非凡的洞察力与推理能力，在护卫李元芳、学生曾泰等人的协助下，破获一系列危及社稷的惊天大案。案件背后交织着蛇灵、铁手团、黑衣社等神秘组织对武周政权的挑战与渗透。狄仁杰以睿智、仁厚和忠勇，一面与女皇武则天周旋于君臣猜忌之间，一面在江湖险境中抽丝剥茧，维护正义。从幽州使团案到邗沟奇案，整个系列充满了悬疑、武侠与权谋色彩，最终狄仁杰在功成之后隐退，留下无数传奇。",
  "characters": [
    {
      "name": "狄仁杰",
      "role_in_story": "绝对主角，当朝宰相，神探",
      "relation_to_protagonist": "自身即主角",
      "traits": ["睿智沉稳", "心怀天下", "推理如神", "幽默仁厚"],
      "must_have": true,
      "voice_style": "不疾不徐，常用‘元芳，你怎么看？’引领推理，台词富含机锋与哲理。",
      "story_arc": "从朝堂重臣到屡破奇案的名相，在一次次生死考验中坚定为国为民之志，最终急流勇退，完成从入世到超脱的蜕变。"
    },
    {
      "name": "李元芳",
      "role_in_story": "狄仁杰的贴身护卫、最信任的助手",
      "relation_to_protagonist": "情同父子的主仆与战友",
      "traits": ["忠诚勇猛", "武功高强", "直率义气", "偶尔鲁莽"],
      "must_have": true,
      "voice_style": "干脆豪爽，常答‘大人真乃神人也！’，行动前必称‘大人，让我去！’",
      "story_arc": "从江湖义士成长为狄仁杰最可靠的左膀右臂，由单纯的武力输出转为能独当一面的探案搭档，并与如燕收获爱情。"
    },
    {
      "name": "如燕",
      "role_in_story": "前蛇灵杀手，后成为狄仁杰义女与李元芳恋人",
      "relation_to_protagonist": "狄仁杰的义女，李元芳的恋人",
      "traits": ["外冷内热", "身世凄苦", "机敏果敢", "痴情"],
      "must_have": true,
      "voice_style": "最初冷漠简练，归正后温柔中带一丝江湖戾气，常唤狄仁杰‘大人’，唤李元芳‘元芳’。",
      "story_arc": "从被蛇灵操控的杀手彻底转变为狄仁杰身边的骨肉至亲，从对情感的恐惧到坚定守护李元芳，完成自我救赎。"
    },
    {
      "name": "肖清芳",
      "role_in_story": "蛇灵组织的大姐，系列首要反派之一",
      "relation_to_protagonist": "狄仁杰的宿敌",
      "traits": ["野心勃勃", "阴险狠毒", "工于心计", "善于伪装"],
      "must_have": true,
      "voice_style": "言辞中带着威压与蛊惑，语调阴柔，常用‘为了蛇灵’掩盖私欲。",
      "story_arc": "从暗中掌控蛇灵到公然反叛朝廷，妄图颠覆武周政权，最终在与狄仁杰的对决中阴谋败露，身死业败。"
    },
    {
      "name": "武则天",
      "role_in_story": "大周皇帝，狄仁杰的君主与最高盟友/对手",
      "relation_to_protagonist": "君臣，既依赖又猜忌",
      "traits": ["雄才大略", "多疑善忌", "杀伐果断", "偶尔念旧"],
      "must_have": false,
      "voice_style": "威严庄重，常常用‘朕’压人，面对狄仁杰又会流露出难得的信任与隐忧。",
      "story_arc": "从对狄仁杰半信半疑到屡次依靠其破局，在权谋与用人之间反复权衡，最终默许狄仁杰的隐退，完成一代女皇的复杂侧面。"
    },
    {
      "name": "曾泰",
      "role_in_story": "狄仁杰的学生，从知县升迁至大理寺卿",
      "relation_to_protagonist": "弟子与得力助手",
      "traits": ["勤勉正直", "谦逊好学", "有时书生意气", "知恩图报"],
